'use client';

import { Check, Copy } from 'lucide-react';
import { useMemo, useState } from 'react';

import { cn } from '@/lib/utils';
import stackOperationsData from '@/registry/default/lib/stack-operations.json';
import {
  generateCurl,
  generateHttpie,
  generateSdk,
  resolvePathParams,
  type TStackOperation,
  type TStackOperationsIndex,
} from '@/components/ui-fragments/_api-snippet/generators';
import { Button } from '@/registry/default/ui/button';
import { CodeSnippet } from '@/registry/default/ui/code/code-snippet';
import { Endpoint } from '@/registry/default/ui/endpoint';
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from '@/registry/default/ui/tabs';

const operations = (stackOperationsData as TStackOperationsIndex).operations;

export type TApiSnippetTab = 'curl' | 'httpie' | 'sdk' | 'fctl';

export type TApiSnippetProps = {
  /** OpenAPI operationId, resolved against the bundled stack operations index. */
  operation: string;
  /** Path parameter values, e.g. `{ ledger: 'testing' }`. */
  params?: Record<string, string>;
  /** Request body. JSON-serialized for curl/sdk, flattened to key=value for HTTPie. */
  body?: Record<string, unknown>;
  /** Extra request headers. */
  headers?: Record<string, string>;
  /** Override the base URL placeholder. */
  baseUrl?: string;
  /** Optional fctl one-liner. When present, an fctl tab is shown. */
  fctl?: string;
  /** Hide the fctl tab even if a fctl prop is provided. */
  noFctl?: boolean;
  /** Initial tab. Defaults to `curl`. */
  defaultTab?: TApiSnippetTab;
  /**
   * Cap the visible height of the code area. When true, long snippets scroll
   * inside the box instead of expanding the parent layout.
   */
  clipCodeHeight?: boolean;
  className?: string;
};

const CLIPPED_CODE_HEIGHT = 240;

export function ApiSnippet({
  operation,
  params,
  body,
  headers,
  baseUrl,
  fctl,
  noFctl,
  defaultTab = 'curl',
  clipCodeHeight = false,
  className,
}: TApiSnippetProps) {
  const codeStyle = clipCodeHeight
    ? { maxHeight: CLIPPED_CODE_HEIGHT }
    : undefined;
  const codeClassName = clipCodeHeight ? 'm-0 overflow-y-auto' : 'm-0';
  const op = operations[operation] as TStackOperation | undefined;
  const method = op?.method ?? 'GET';
  const rawPath = op?.path ?? '';
  const resolvedPath = resolvePathParams(rawPath, params);
  const showFctl = !noFctl && !!fctl;

  const curl = useMemo(
    () => generateCurl(method, resolvedPath, body, headers, baseUrl),
    [method, resolvedPath, body, headers, baseUrl]
  );
  const httpie = useMemo(
    () => generateHttpie(method, resolvedPath, body, headers, baseUrl),
    [method, resolvedPath, body, headers, baseUrl]
  );
  const sdk = useMemo(
    () => (op ? generateSdk(op, params, body) : ''),
    [op, params, body]
  );

  const initialTab: TApiSnippetTab =
    defaultTab === 'fctl' && !showFctl ? 'curl' : defaultTab;
  const [tab, setTab] = useState<TApiSnippetTab>(initialTab);

  if (!op) {
    return (
      <div
        className={cn(
          'rounded-md border border-destructive/40 bg-destructive/10 p-3 font-mono text-xs text-destructive-foreground',
          className
        )}
      >
        Unknown operation: <code>{operation}</code>
      </div>
    );
  }

  const codeByTab: Record<TApiSnippetTab, string> = {
    curl,
    httpie,
    sdk,
    fctl: fctl ?? '',
  };

  return (
    <div
      className={cn(
        'not-prose w-full overflow-hidden rounded-md border bg-card text-card-foreground',
        className
      )}
    >
      <Tabs
        value={tab}
        onValueChange={(v) => setTab(v as TApiSnippetTab)}
        className="gap-0"
      >
        <div className="flex items-center border-b bg-muted/40 pr-2">
          <TabsList variant="line" className="px-2 pl-0 -ml-px">
            {showFctl && <TabsTrigger value="fctl">fctl</TabsTrigger>}
            <TabsTrigger value="curl">curl</TabsTrigger>
            <TabsTrigger value="httpie">HTTPie</TabsTrigger>
            <TabsTrigger value="sdk">TypeScript</TabsTrigger>
          </TabsList>
          <CopyButton text={codeByTab[tab]} className="ml-auto" />
        </div>
        <TabsContent
          value="curl"
          className={codeClassName}
          style={codeStyle}
        >
          <CodeSnippet
            code={curl}
            language="bash"
            bordered={false}
            canCopy={false}
          />
        </TabsContent>
        <TabsContent
          value="httpie"
          className={codeClassName}
          style={codeStyle}
        >
          <CodeSnippet
            code={httpie}
            language="bash"
            bordered={false}
            canCopy={false}
          />
        </TabsContent>
        <TabsContent
          value="sdk"
          className={codeClassName}
          style={codeStyle}
        >
          <CodeSnippet
            code={sdk}
            language="typescript"
            bordered={false}
            canCopy={false}
          />
        </TabsContent>
        {showFctl && (
          <TabsContent
            value="fctl"
            className={codeClassName}
            style={codeStyle}
          >
            <CodeSnippet
              code={fctl!}
              language="bash"
              bordered={false}
              canCopy={false}
            />
          </TabsContent>
        )}
      </Tabs>
      <div className="flex items-center border-t p-2">
        <Endpoint method={op.method} path={resolvedPath.split('?')[0]} />
      </div>
    </div>
  );
}

function CopyButton({ text, className }: { text: string; className?: string }) {
  const [copied, setCopied] = useState(false);

  return (
    <Button
      variant="outline"
      size="icon-sm"
      aria-label="Copy"
      className={cn('text-muted-foreground', className)}
      onClick={async () => {
        await navigator.clipboard.writeText(text.trim());
        setCopied(true);
        setTimeout(() => setCopied(false), 1500);
      }}
    >
      {copied ? <Check /> : <Copy />}
    </Button>
  );
}

export type TStackOperation = {
  method: 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE' | 'HEAD' | 'OPTIONS';
  path: string;
  pathParams: string[];
  sdk: { module: string; method: string };
  summary?: string;
  tags?: string[];
};

export type TStackOperationsIndex = {
  _meta?: { specVersion?: string; specFile?: string };
  operations: Record<string, TStackOperation>;
};

export function resolvePathParams(
  path: string,
  params?: Record<string, string>
): string {
  if (!params) return path;
  let resolved = path;
  for (const [k, v] of Object.entries(params))
    resolved = resolved.replace(`{${k}}`, v);

  return resolved;
}

export function generateCurl(
  method: string,
  path: string,
  body?: unknown,
  headers?: Record<string, string>,
  baseUrl = '$FORMANCE_API_URL'
): string {
  const parts = [`curl -X ${method} ${baseUrl}${path}`];
  if (headers) {
    for (const [k, v] of Object.entries(headers))
      parts.push(`  -H "${k}: ${v}"`);
  }
  if (body) {
    const formatted = JSON.stringify(body, null, 2);
    const indented = formatted
      .split('\n')
      .map((l, i) => (i === 0 ? l : '  ' + l))
      .join('\n');
    parts.push(`  -H "Content-Type: application/json"`);
    parts.push(`  -d '${indented}'`);
  }

  return parts.join(' \\\n');
}

function jsonDepth(val: unknown): number {
  if (typeof val !== 'object' || val === null) return 0;
  if (Array.isArray(val)) return 1 + Math.max(0, ...val.map(jsonDepth));

  return (
    1 +
    Math.max(0, ...Object.values(val as Record<string, unknown>).map(jsonDepth))
  );
}

function flattenHttpieArgs(
  obj: Record<string, unknown>,
  prefix: string,
  parts: string[],
  depth = 0
) {
  for (const [k, v] of Object.entries(obj)) {
    const key = prefix ? `${prefix}[${k}]` : k;
    if (v === null || v === undefined) continue;
    if (typeof v === 'string') {
      const needsQuote = /[\s[\](){}$@|&;!<>'"\\]/.test(v);
      parts.push(needsQuote ? `  ${key}='${v}'` : `  ${key}=${v}`);
    } else if (typeof v === 'number' || typeof v === 'boolean') {
      parts.push(`  ${key}:=${String(v)}`);
    } else if (Array.isArray(v)) {
      parts.push(`  ${key}:='${JSON.stringify(v)}'`);
    } else if (typeof v === 'object') {
      if (depth >= 1 || Object.keys(v as object).length === 0) {
        parts.push(`  ${key}:='${JSON.stringify(v)}'`);
      } else {
        flattenHttpieArgs(v as Record<string, unknown>, key, parts, depth + 1);
      }
    }
  }
}

export function generateHttpie(
  method: string,
  path: string,
  body?: unknown,
  headers?: Record<string, string>,
  baseUrl = '$FORMANCE_API_URL'
): string {
  const verb = method === 'GET' ? '' : method + ' ';
  const [basePath, queryString] = path.split('?');
  const parts = [`http ${verb}${baseUrl}${basePath}`];
  if (queryString) {
    for (const param of queryString.split('&')) {
      const [k, v] = param.split('=');
      parts.push(`  ${k}==${v}`);
    }
  }
  if (headers) {
    for (const [k, v] of Object.entries(headers)) parts.push(`  ${k}:${v}`);
  }
  if (body && typeof body === 'object' && !Array.isArray(body)) {
    if (jsonDepth(body) > 2) {
      const formatted = JSON.stringify(body, null, 2);
      const indented = formatted
        .split('\n')
        .map((l) => '  ' + l)
        .join('\n');
      parts.push(`  <<< '`);
      parts.push(indented);
      parts.push(`  '`);
    } else {
      flattenHttpieArgs(body as Record<string, unknown>, '', parts);
    }
  } else if (body) {
    parts.push(`  <<< '${JSON.stringify(body)}'`);
  }

  return parts.join(' \\\n');
}

export function generateSdk(
  op: TStackOperation,
  params?: Record<string, string>,
  body?: Record<string, unknown>
): string {
  const args: Record<string, unknown> = { ...(params ?? {}) };
  if (body && typeof body === 'object' && !Array.isArray(body))
    Object.assign(args, body);

  const argsBlock = Object.keys(args).length
    ? JSON.stringify(args, null, 2)
        .split('\n')
        .map((l, i) => (i === 0 ? l : '  ' + l))
        .join('\n')
    : '{}';

  return [
    `import { SDK } from '@formance/formance-sdk';`,
    ``,
    `const client = new SDK({ serverURL: process.env.FORMANCE_API_URL });`,
    ``,
    `const response = await client.${op.sdk.module}.${op.sdk.method}(${argsBlock});`,
  ].join('\n');
}
